// ─────────────────────────────────────────────────────────────────────────────
//  #47: Precision-safe rounding helper
// ─────────────────────────────────────────────────────────────────────────────

export function roundPct(value, decimals = 3) {
  const factor = 10 ** decimals;
  return Math.round(value * factor) / factor;
}
